import * as signalR from '@microsoft/signalr';
if (document.querySelector('.dropdown-notify')) {
    const connection = new signalR.HubConnectionBuilder()
        .withUrl('/NotificationHub')
        .withAutomaticReconnect().configureLogging(signalR.LogLevel.Error)
        .build();
    connection.on('newActivityAsync', (alerts) => {
        const alert = document.getElementById('notificationAlert');
        const notifyLink = document.getElementById('notificationLink');
        if (alerts > 0 && notifyLink.classList.contains('d-none')) {
            notifyLink.classList.toggle('d-none');
            alert.classList.toggle('d-none');
        }
    });
    connection.start();
    document.addEventListener('DOMContentLoaded', () => {
        const alert = document.getElementById('notificationAlert');
        const notifyLink = document.getElementById('notificationLink');
        if (alert !== null && parseInt(alert.dataset.alerts || '0', 10) > 0) {
            notifyLink.classList.toggle('d-none');
            alert.classList.toggle('d-none');
        }
    });
}
